import{_ as e,c as s,o as n,ag as t}from"./chunks/framework.ELrfyV9R.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/xiangxiang103/status/2038869749036392824","created":"2026-03-31T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/Claude：这活我不干了，Codex 你来.md","filePath":"ai/bookmark/Claude：这活我不干了，Codex 你来.md","lastUpdated":1775818659000}'),p={name:"ai/bookmark/Claude：这活我不干了，Codex 你来.md"};function o(l,a,i,d,c,r){return n(),s("div",null,a[0]||(a[0]=[t(`<blockquote><p>本文记录了在 Claude Code 中安装 OpenAI Codex 插件、完成配置并实测编程任务委托的完整过程。<strong>测试环境：</strong> Windows 10，Mac/Linux 用户路径格式会有所不同（如 ~/.claude/ 而非 C:/Users/你的用户名/.claude/），其余步骤一致。</p></blockquote><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p><strong>OpenAI Codex CLI</strong> 是 OpenAI 官方发布的命令行编程工具，底层使用 GPT系列模型，专为代码任务优化，支持读写本地文件、执行命令、调试代码等。</p><p>OpenAI 为 Claude Code 发布了 codex-plugin-cc 插件，允许你在 Claude Code 会话中直接将编程任务委托给本地运行的 Codex CLI，实现 <strong>Claude + Codex 双模型协同工作</strong>。</p><p>什么时候用 Codex，什么时候直接用 Claude？</p><p><img src="https://pbs.twimg.com/media/HEuEyAvaoAAt6wO?format=png&amp;name=large" alt="图像"></p><p>费用说明</p><p>使用 codex:rescue 会调用 <strong>OpenAI API</strong>，按实际 token 消耗计费，费率取决于所用模型。与 Claude Code 的 Anthropic 额度<strong>相互独立</strong>，需要单独的 OpenAI API Key 或账号余额。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>已安装 Claude Code CLI</li><li>已安装 Node.js（v18+）和 npm</li><li>已有 OpenAI 账号（需要 API 额度）</li></ul><h2 id="第一步-添加插件市场源" tabindex="-1">第一步：添加插件市场源 <a class="header-anchor" href="#第一步-添加插件市场源" aria-label="Permalink to &quot;第一步：添加插件市场源&quot;">​</a></h2><p>在 Claude Code 中运行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add openai/codex-plugin-cc</span></span></code></pre></div><p><strong>预期输出：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Successfully added marketplace: openai-codex</span></span></code></pre></div><p>这一步将 OpenAI 官方的插件市场源添加到 Claude Code 中。</p><h2 id="第二步-安装-codex-插件" tabindex="-1">第二步：安装 Codex 插件 <a class="header-anchor" href="#第二步-安装-codex-插件" aria-label="Permalink to &quot;第二步：安装 Codex 插件&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install codex@openai-codex</span></span></code></pre></div><p><strong>预期输出：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Installed codex. Run /reload-plugins to apply.</span></span></code></pre></div><h2 id="第三步-重载插件" tabindex="-1">第三步：重载插件 <a class="header-anchor" href="#第三步-重载插件" aria-label="Permalink to &quot;第三步：重载插件&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/reload-plugins</span></span></code></pre></div><p><strong>预期输出：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reloaded: 5 plugins · 7 skills · 6 agents · 3 hooks · 1 plugin MCP server · 0 plugin LSP servers</span></span></code></pre></div><p>重载后，Codex 相关技能（codex:setup、codex:rescue 等）才会生效。</p><h2 id="第四步-检查-codex-环境" tabindex="-1">第四步：检查 Codex 环境 <a class="header-anchor" href="#第四步-检查-codex-环境" aria-label="Permalink to &quot;第四步：检查 Codex 环境&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex:setup</span></span></code></pre></div><p><img src="https://pbs.twimg.com/media/HEt4_-ebMAAU_0T?format=jpg&amp;name=large" alt="图像"></p><p>这个命令会自动检测本地环境，输出类似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;ready&quot;: true,</span></span>
<span class="line"><span>  &quot;node&quot;: { &quot;available&quot;: true, &quot;detail&quot;: &quot;v24.12.0&quot; },</span></span>
<span class="line"><span>  &quot;npm&quot;:  { &quot;available&quot;: true, &quot;detail&quot;: &quot;11.6.2&quot; },</span></span>
<span class="line"><span>  &quot;codex&quot;: { &quot;available&quot;: true, &quot;detail&quot;: &quot;codex-cli 0.117.0; advanced runtime available&quot; },</span></span>
<span class="line"><span>  &quot;auth&quot;: { &quot;available&quot;: true, &quot;loggedIn&quot;: true, &quot;detail&quot;: &quot;authenticated&quot; }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>各字段含义：</strong></p><p><img src="https://pbs.twimg.com/media/HEt5MRjbMAAquyf?format=png&amp;name=large" alt="图像"></p><p><strong>如果 Codex CLI 未安装</strong></p><p>/codex:setup 会提示你安装，选择 <strong>Install Codex (Recommended)</strong>，它会自动运行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install -g @openai/codex</span></span></code></pre></div><p><strong>如果未登录</strong></p><p>安装完成后在终端运行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codex login</span></span></code></pre></div><p>完成 OpenAI 授权后重新运行 /codex:setup 验证。</p><p><strong>可选：开启 Review Gate</strong></p><p>/codex:setup 输出里有一条可选建议：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex:setup --enable-review-gate</span></span></code></pre></div><p>开启后，每次 Codex 执行任务前会<strong>强制要求人工审核</strong>，确认无误再继续。适合对代码修改比较谨慎、或在重要项目中使用的场景。不开启则默认自动执行。</p><h2 id="第五步-实测——委托-codex-编写代码" tabindex="-1">第五步：实测——委托 Codex 编写代码 <a class="header-anchor" href="#第五步-实测——委托-codex-编写代码" aria-label="Permalink to &quot;第五步：实测——委托 Codex 编写代码&quot;">​</a></h2><p>使用方式</p><p>安装完成后，<strong>直接用自然语言描述任务</strong>即可，不需要手动输入 /codex:rescue。Claude 会自动判断任务复杂度并决定是否调用 Codex。</p><p>你也可以在描述任务时明确说&quot;交给 Codex 处理&quot;，Claude 会立即委托。</p><p><strong>示例任务：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写一个 Python 脚本，读取 CSV 文件并统计每列的均值，交给 Codex 处理</span></span></code></pre></div><p><strong>Codex 输出结果：</strong></p><p>Codex 生成了一个完整的 Python 脚本 csv_stats.py，包含命令行参数解析、数值列自动识别、UTF-8/GBK 编码兼容、以及多种异常处理。</p><p><img src="https://pbs.twimg.com/media/HEt6OilboAAqkqL?format=jpg&amp;name=large" alt="图像"></p><p><strong>运行效果：</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文件：data.csv</span></span>
<span class="line"><span>共找到 3 列数值列</span></span>
<span class="line"><span></span></span>
<span class="line"><span>列名            均值</span></span>
<span class="line"><span>---------------------------</span></span>
<span class="line"><span>age            34.2500</span></span>
<span class="line"><span>salary      75000.0000</span></span>
<span class="line"><span>score           88.5000</span></span></code></pre></div><h2 id="最佳实践-让-claude-review-codex-的输出" tabindex="-1">最佳实践：让 Claude Review Codex 的输出 <a class="header-anchor" href="#最佳实践-让-claude-review-codex-的输出" aria-label="Permalink to &quot;最佳实践：让 Claude Review Codex 的输出&quot;">​</a></h2><p>Codex 是独立模型，Claude 不参与代码生成过程。建议每次委托完成后，追加一句：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我 review 一下刚才 Codex 生成的代码</span></span></code></pre></div><p>Claude 会从逻辑正确性、异常处理、安全性等角度把关，再由你决定是否使用。</p><p><strong>以本次示例为例，review 结论：</strong></p><ul><li>逻辑正确，均值计算和数值列识别无误</li><li>异常处理完整，覆盖文件不存在、无权限、编码错误、空文件等场景</li><li>编码兼容性好，UTF-8 + GBK 自动回退，适合 Windows 环境</li><li>无安全问题，只读文件操作，无命令注入风险</li><li>可直接使用</li></ul><p>这一步不是必须的，但养成习惯后能有效避免 Codex 输出质量不稳定带来的问题。</p><h2 id="工作流程解析" tabindex="-1">工作流程解析 <a class="header-anchor" href="#工作流程解析" aria-label="Permalink to &quot;工作流程解析&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的自然语言需求</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>   Claude 分析（自动判断是否委托）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  调用 codex:rescue 技能</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  codex-companion.mjs（本地脚本）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  OpenAI Codex CLI（本地运行）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  GPT系列模型处理（消耗 OpenAI 额度）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  生成代码文件 + 返回结果</span></span></code></pre></div><p>关键点：Codex CLI <strong>在本地运行</strong>，通过你的 OpenAI API Key 调用云端模型，结果文件直接写入当前工作目录。</p><h2 id="可用技能一览" tabindex="-1">可用技能一览 <a class="header-anchor" href="#可用技能一览" aria-label="Permalink to &quot;可用技能一览&quot;">​</a></h2><p>安装插件后，Claude Code 新增以下技能：</p><p><img src="https://pbs.twimg.com/media/HEt7v63aAAAwdwz?format=png&amp;name=large" alt="图像"></p><p><strong>codex:rescue 支持的参数</strong></p><p><img src="https://pbs.twimg.com/media/HEt75QEasAAkPnn?format=png&amp;name=large" alt="图像"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：/codex:setup 运行后提示 Codex 未安装怎么办？</strong></p><p>选择 Install Codex (Recommended)，插件会自动运行 npm install -g <a href="https://x.com/@openai/codex" target="_blank" rel="noreferrer">@openai/codex</a>。</p><p><strong>Q：安装后提示未认证怎么办？</strong></p><p>在系统终端运行 codex login，完成 OpenAI 账号授权。</p><p><strong>Q：任务结束后想继续追问 Codex 怎么办？</strong></p><p>再次描述需求，如果检测到可恢复的会话，Claude 会询问是否继续当前线程还是开启新线程。</p><p><strong>Q：用了 Codex 会产生 OpenAI 费用吗？</strong></p><p>是的。每次调用 codex:rescue 都会消耗 OpenAI API 额度，与 Claude Code 的 Anthropic 账单独立计算。建议在 OpenAI 控制台设置用量限额。</p><p><strong>Q：Mac/Linux 上路径不一样怎么办？</strong></p><p>本文路径示例基于 Windows。Mac/Linux 上插件缓存路径为 ~/.claude/plugins/cache/，其余命令完全一致。</p><h2 id="💡-下一步行动" tabindex="-1">💡 下一步行动 <a class="header-anchor" href="#💡-下一步行动" aria-label="Permalink to &quot;💡 下一步行动&quot;">​</a></h2><p>看完教程后，建议你现在就在终端运行 /codex:setup 检查一下环境。</p><p>配好后找个小任务试试手，感受下 Claude + Codex 双模型协同的效率。</p><p>遇到问题欢迎在评论区交流，我会持续更新踩坑记录。</p>`,84)]))}const h=e(p,[["render",o]]);export{g as __pageData,h as default};
